// Write a function to validate whether a given string of HTML tags is valid.
// A string of HTML tags is valid if it consists of well-formed HTML elements,
// i.e., each opening tag is followed by a corresponding closing tag.
// The function should return true if the input string is valid, false otherwise.
function isValidHtml(s) {
    let stack = [];
    let i = 0;
    while (i < s.length) {
        if (s[i] === '<') {
            let j = i + 1;
            let tagName = '';
            while (j < s.length && s[j] !== '>') {
                tagName += s[j++];
            }
            stack.push(tagName);
            i = j;
        } else if (s[i] === '>') {
            i++;
        } else {
            i++;
        }
    }
    while (stack.length > 0) {
        let tagName = stack.pop();
        if (tagName !== 'div' && tagName !== 'p') {
            return false;
        }
    }
    return true;
}

