class Solution:
    def isValidHtml(self, s: str) -> bool:
        stack = []
        i = 0
        while i < len(s):
            if s[i] == '<':
                j = s.find('>', i + 1)
                if j != -1:
                    tag_name = s[i + 1:j]
                    stack.append(tag_name)
                    i = j
                else:
                    i += 1
            elif s[i] == '>':
                i += 1
            else:
                i += 1
        while len(stack) > 0:
            tag_name = stack.pop()
            if tag_name not in ['div', 'p']:
                return False
        return True
